const ARTWORKS = [
    { name: 'Mona Lisa', cols: 13, pixels: MONA_PIXELS },
    { name: 'Night', cols: 38, pixels: NIGHT_PIXELS },
    { name: 'adam', cols: 44, pixels: ADAM_PIXELS },
    { name: 'kanagawa', cols: 30, pixels: KANAGAWA_PIXELS },
    { name: 'glaneuses', cols: 43, pixels: GLANEUSES_PIXELS },
    { name: 'blacklotus', cols: 41, pixels: BLACKLOTUS_PIXELS },
    { name: 'guernica', cols: 52, pixels: GUERNICA_PIXELS },
];

function _hexToRgb(hex) {
    return {
        r: parseInt(hex.substring(0, 2), 16),
        g: parseInt(hex.substring(2, 4), 16),
        b: parseInt(hex.substring(4, 6), 16),
    };
}

function _nearestColorIdx(r, g, b) {
    let best = 0;
    let bestDist = Infinity;
    for (let i = 0; i < 256; i++) {
        const c = PALETTE[i];
        const dr = r - ((c >> 16) & 0xFF);
        const dg = g - ((c >> 8) & 0xFF);
        const db = b - (c & 0xFF);
        const d = dr * dr + dg * dg + db * db;
        if (d < bestDist) {
            bestDist = d;
            best = i;
        }
    }
    return best;
}

export class Art extends CmdBase {
    static get commandName() { return 'art'; }
    static get help() { return 'Render ASCII art from a random artwork'; }
    static get menu() { return 'ASCII art'; }

    execute(args) {
        const artwork = ARTWORKS[Math.floor(Math.random() * ARTWORKS.length)];
        const COLS = artwork.cols;
        const ROWS = artwork.pixels.length / COLS;
        const pixels = artwork.pixels;
        let out = '';
        for (let y = 0; y < ROWS; y += 2) {
            for (let x = 0; x < COLS; x++) {
                const upperHex = pixels[y * COLS + x];
                const lowerHex = y + 1 < ROWS ? pixels[(y + 1) * COLS + x] : '000000';
                const u = _hexToRgb(upperHex);
                const l = _hexToRgb(lowerHex);
                const fg = _nearestColorIdx(u.r, u.g, u.b);
                const bg = _nearestColorIdx(l.r, l.g, l.b);
                out += `\x1B[38;5;${fg};48;5;${bg}m▀\x1B[0m`;
            }
            out += '\n';
        }
        this.print(out);
    }
}
